import{_ as t,o as a,c as n,a2 as o}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"Deployments","description":"","frontmatter":{},"headers":[],"relativePath":"app/deployments.md","filePath":"app/deployments.md"}'),r={name:"app/deployments.md"};function s(l,e,i,d,h,p){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="deployments" tabindex="-1">Deployments <a class="header-anchor" href="#deployments" aria-label="Permalink to &quot;Deployments&quot;">‚Äã</a></h1><p>A deployment runs the build-and-release pipeline for an <a href="/app/environments">environment</a>: Tragwerk clones the branch, builds the Docker image and starts the containers. Each run is a <strong>deploy job</strong> you can watch live and revisit later in the deployment history.</p><h2 id="deploy-job-statuses" tabindex="-1">Deploy job statuses <a class="header-anchor" href="#deploy-job-statuses" aria-label="Permalink to &quot;Deploy job statuses&quot;">‚Äã</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Pending</strong></td><td>The job is queued and waiting to start.</td></tr><tr><td><strong>Running</strong></td><td>The build/deploy is in progress.</td></tr><tr><td><strong>Completed</strong></td><td>The deployment finished successfully.</td></tr><tr><td><strong>Failed</strong></td><td>The deployment stopped with an error.</td></tr></tbody></table><h2 id="what-triggers-a-deployment" tabindex="-1">What triggers a deployment <a class="header-anchor" href="#what-triggers-a-deployment" aria-label="Permalink to &quot;What triggers a deployment&quot;">‚Äã</a></h2><ul><li><strong>Git push webhook</strong> ‚Äî pushing to a branch that maps to an environment.</li><li><strong>Manual redeploy</strong> ‚Äî the <strong>Redeploy</strong> button on an <a href="/app/environments">environment</a> re-deploys the latest commit.</li></ul><h2 id="the-deployments-view" tabindex="-1">The deployments view <a class="header-anchor" href="#the-deployments-view" aria-label="Permalink to &quot;The deployments view&quot;">‚Äã</a></h2><p>Open <strong>Deployments</strong> for the active environment to see a two-pane view:</p><ul><li>On the left, the <strong>history list</strong> of build and deploy log entries. You can filter by type (all, build, deploy) and load older entries.</li><li>On the right, the <strong>terminal</strong> showing the selected entry&#39;s output, with its status badge, commit, duration and timestamp, plus <strong>Copy</strong> and <strong>Download</strong> buttons.</li></ul><h2 id="live-log-streaming" tabindex="-1">Live log streaming <a class="header-anchor" href="#live-log-streaming" aria-label="Permalink to &quot;Live log streaming&quot;">‚Äã</a></h2><p>While a job is <strong>Pending</strong> or <strong>Running</strong>, its terminal streams output in real time, appending each line as it arrives with a blinking cursor while the job is active.</p><h2 id="example-follow-a-deploy-after-pushing" tabindex="-1">Example: follow a deploy after pushing <a class="header-anchor" href="#example-follow-a-deploy-after-pushing" aria-label="Permalink to &quot;Example: follow a deploy after pushing&quot;">‚Äã</a></h2><ol><li>Push to a branch that has an environment, or click <strong>Redeploy</strong>.</li><li>Open the environment ‚Äî the new job appears in the <strong>Deployments</strong> table with a <strong>Pending</strong>/<strong>Running</strong> badge.</li><li>Select it to open the terminal and watch the log stream until the badge turns <strong>Completed</strong> (or <strong>Failed</strong>).</li></ol><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">‚Äã</a></h2><ul><li><a href="/app/environments">Environments</a></li><li><a href="/app/projects">Projects</a></li><li><a href="/app/integrations">Integrations</a></li></ul>',15)])])}const u=t(r,[["render",s]]);export{m as __pageData,u as default};
